// src/logger.ts
var logger = {
  info(message, meta) {
    meta ? console.log("[INFO]", message, meta) : console.log("[INFO]", message);
  },
  warn(message, meta) {
    meta ? console.warn("[WARN]", message, meta) : console.warn("[WARN]", message);
  },
  error(message, meta) {
    meta ? console.error("[ERROR]", message, meta) : console.error("[ERROR]", message);
  }
};

