var workerPoolInstance = null;
function getWorkerPool() {
  if (!workerPoolInstance) {
    const defaultOptions = {
      minWorkers: 1,
      maxWorkers: 10,
      idleTimeout: 3e4,
      // 30 seconds
      taskTimeout: 6e4,
      // 60 seconds
      maxRetries: 3,
      scalingThreshold: 0.8,
      // Scale when 80% of workers are busy
      logger: {
        log: (message) => logger.info(`[WorkerPool] ${message}`),
        warn: (message) => logger.warn(`[WorkerPool] ${message}`),
        error: (message, error) => logger.error(`[WorkerPool] ${message}`, error)
      }
    };
    workerPoolInstance = new WorkerPool(defaultOptions);
  }
  return workerPoolInstance;
}
async function shutdownWorkerPool() {
  if (workerPoolInstance) {
    await workerPoolInstance.shutdown();
    workerPoolInstance = null;
  }
}
function getWorkerPoolStats() {
  return workerPoolInstance?.getStats() || null;
}
